#!/usr/bin/env bash
# topic-1.sh — —— 决策助手 for B2B 大客户销售.
# Auto-generated by cli_writer.py. Source: synthesis.md Section 2 (Playbook).
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="B2B 大客户销售"
TOPIC="——"

usage() {
  cat <<EOF
topic-1.sh — ${TOPIC} 决策助手 for ${INDUSTRY}

基于 5 条 playbook 规则的交互式决策评估。
你描述情景, 工具帮你判断哪条规则适用, 并给推荐。

USAGE:
  ./topic-1.sh             # interactive
  ./topic-1.sh --dry-run   # walk through but no file
  ./topic-1.sh --json      # JSON to stdout
  ./topic-1.sh --explain   # show backing playbook rules + mental models
  ./topic-1.sh --help      # this message
EOF
}

explain() {
  cat <<'EOT'
这个决策助手把 —— 主题下的 playbook 规则组合成交互树。

基于 5 条规则:
  • 如果 买方要 POC 但不肯共签书面 success criteria 与时间盒 → 则 不启动 POC——先回 discovery 补痛点与 EB
  • 如果 采购/客户压价 → 则 永不白送折扣——每个让步换一个对价(更快的 paper process / 多年期 / 可引用案例 / 扩 scope)
  • 如果 你以为有 champion 但他没为你做过任何内部的事 → 则 测试他:请他拉一场带 EB 的会/给组织架构/预演你的 business case——做不到的是 coach 不是 ch
  • 如果 outbound 回复率/送达率崩了 → 则 别加量——切 signal-based 定向(招聘信号/换帅/融资等触发器)+ 按地域过合规闸(美国电话查 TCPA 同
  • 如果 季度开局 pipeline coverage 低于约三倍 quota(业内经验法则,无单一权威源) → 则 把日历优先级翻给 pipeline generation 而非只盯晚期单——本月不开口,90 天后没单

相关心智模型:
  • 问 ⇄ 教 ⇄ 筛:三派第一性张力,资深人按层混用: 复杂销售的方法论分三派——诊断式提问(SPIN/Gap:「客户有答案,问到痛点不可否认为止」)⇄ 挑战式教学(Challenger:「客户对自己问题的认知是错的,用商业洞见 reframe」)⇄ 资格
  • 头号对手是「不决策」,不是竞品: 预测内丢单的最大去向不是输给对手,而是客户「什么都不做」——维持现状;且一旦购买意向形成,买方更怕「搞砸」(FOMU)而非「错过」(FOMO),所以晚期停滞要按「犹豫」处理(去风险),不是按「异议」处

来源: synthesis.md Section 2.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a RULE_CONDITIONS=(
  "买方要 POC 但不肯共签书面 success criteria 与时间盒"
  "采购/客户压价"
  "你以为有 champion 但他没为你做过任何内部的事"
  "outbound 回复率/送达率崩了"
  "季度开局 pipeline coverage 低于约三倍 quota(业内经验法则,无单一权威源)"
)
declare -a RULE_ACTIONS=(
  "不启动 POC——先回 discovery 补痛点与 EB"
  "永不白送折扣——每个让步换一个对价(更快的 paper process / 多年期 / 可引用案例 / 扩 scope),用校准问题(「How am I supposed to do that?」)代替对抗"
  "测试他:请他拉一场带 EB 的会/给组织架构/预演你的 business case——做不到的是 coach 不是 champion"
  "别加量——切 signal-based 定向(招聘信号/换帅/融资等触发器)+ 按地域过合规闸(美国电话查 TCPA 同意、EU 邮件走 legitimate interest 评估、加拿大 CASL opt-in),量是送达率的敌人"
  "把日历优先级翻给 pipeline generation 而非只盯晚期单——本月不开口,90 天后没单"
)
declare -a APPLIED_RULES=()

ms_section "${INDUSTRY} · ${TOPIC} 决策评估"
ms_info "本工具基于 ${#RULE_CONDITIONS[@]} 条 playbook 规则评估你的情景。"
echo

ms_prompt "请描述当前情景 (空行结束):"
echo
SITUATION="$(ms_read_multiline)"

for i in "${!RULE_CONDITIONS[@]}"; do
  ms_section "Rule $((i+1))/${#RULE_CONDITIONS[@]}"
  echo "适用情景: ${RULE_CONDITIONS[$i]}"
  echo "推荐做法: ${RULE_ACTIONS[$i]}"
  if ms_confirm "这条规则 fit 你当前情景吗?"; then
    APPLIED_RULES+=("$((i+1))")
    ms_ok "适用 rule $((i+1))"
  fi
done

ms_buffer_append "# ${INDUSTRY} — ${TOPIC} 决策报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## 情景"
ms_buffer_append ""
ms_buffer_append "$SITUATION"
ms_buffer_append ""
ms_buffer_append "## 适用规则"
ms_buffer_append ""
if [[ ${#APPLIED_RULES[@]} -eq 0 ]]; then
  ms_buffer_append "(无适用 playbook 规则 — 此情景在已知 OS 之外, 建议回到 SKILL.md 心智模型层重新分析)"
else
  for ridx in "${APPLIED_RULES[@]}"; do
    i=$((ridx-1))
    ms_buffer_append "- **情景**: ${RULE_CONDITIONS[$i]} → **做法**: ${RULE_ACTIONS[$i]}"
  done
fi
ms_buffer_append ""

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "topic" "${TOPIC}" \
    "situation" "${SITUATION}" \
    "applied_rules_count" "${#APPLIED_RULES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "topic-1-decision"
fi
